                        {/* Status Pill */}
                        <div className="glass px-3 py-1.5 rounded-full flex items-center gap-2">
                            <span className={`w-2 h-2 rounded-full animate-pulse ${status.isOpen ? 'bg-[#25D366]' : 'bg-[#FF2D2D]'}`}></span>
